          // ÑÐ¶Ðµ ÑÐ»ÐµÐ½Ð³ â Ð½Ðµ ÑÑÐ¾Ð³Ð°ÐµÐ¼
          if (SLANG.has(text.toLowerCase().trim())) return text;

          var result = text.toLowerCase().replace(/\.$/, '').trim();

