      if (this._pSvvx == null) { this._pSvvx = this.svx; this._pSvvy = this.svy; }

      const dvx = this.svx - this._pSvvx;
      const dvy = this.svy - this._pSvvy;

      const ax = dvx / dt;
      const ay = dvy / dt;
      const am = Math.hypot(ax, ay);

      this.sax = ax;
      this.say = ay;
      this.saccel = am;

      _updateAccelWindows(this, ax, ay, am, ticksPerUpdate, TICK);

      this._pSvvx = this.svx;
      this._pSvvy = this.svy;

