// ===== Ð ÐÐÐÐÐ  Ð¢ÐÐ ÐÐ =====
const tiersContainer = document.getElementById('rvc-autospawn-tiers');

for (let tier = 1; tier <= 16; tier++) {
  const animals = TIER_ANIMALS[tier] || [];
  const key = 'tier' + tier;
  const currentVal = RVJsettings.autoSpawnSettings[key] ?? animals[0]?.id ?? 0;

  const row = document.createElement('div');
  row.style.cssText = `
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 6px 10px;
  `;

  const label = document.createElement('span');
  label.style.cssText = `
    font-family: 'Oxanium', sans-serif;
    font-size: 15px;
    font-weight: 300;
    color: white;
  `;
  label.textContent = `Tier ${tier}`;

  const select = document.createElement('select');
  select.className = 'rvc-dropdown';
  select.style.cssText = `
    position: static;
    width: auto;
    min-width: 140px;
    height: 26px;
    border-radius: 4px;
    outline: 2px solid #7A5CF1;
    background: #4A4B57;
    color: white;
    font-family: 'Oxanium', sans-serif;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    padding: 0 4px;
    border: none;
  `;

  animals.forEach(animal => {
    const opt = document.createElement('option');
    opt.value = animal.id;
    opt.textContent = animal.name;
    if (animal.id === currentVal) opt.selected = true;
    select.appendChild(opt);
  });

  if (animals.length === 0) {
    const opt = document.createElement('option');
    opt.textContent = 'None';
    select.appendChild(opt);
    select.disabled = true;
  }

  select.addEventListener('change', () => {
    RVJsettings.autoSpawnSettings[key] = Number(select.value);
    localStorage.setItem('RVJsettings', JSON.stringify(RVJsettings));
  });

  row.appendChild(label);
  row.appendChild(select);
  tiersContainer.appendChild(row);
}

